var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라? 여기서 못 보던 아줌마네?","JPN":"あれ？　初めて見るおばさんだね？","ENG":"Huh? You're someone I've never seen before.","TWN":"嗯？是我沒見過的阿姨欸？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"아줌마는 누구야?","JPN":"おばさん誰？","ENG":"Who's this old lady?","TWN":"阿姨你是誰啊？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……아줌마?","JPN":"……おばさん？","ENG":"...What did you call me?","TWN":"……阿姨？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야! 이래 봬도 졸업한 뒤에 곧바로 채용시험에서 합격한 거거든?","JPN":"おい、こう見えてもアタシは卒業後すぐに採用試験に合格してるんだぞ！","ENG":"Hey! I got a job as soon as I graduated!","TWN":"喂！我也才畢業工作沒多久欸。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"많아 봤자, 너랑 서너 살 차이밖에 안 난다고!","JPN":"おまえと3、4歳しか変わらないんだからな！","ENG":"Even if I'm old, you and I are only three or four years apart!","TWN":"我頂多只比你大三、四歲而已！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"호오, 그래?","JPN":"へえ、そう？","ENG":"Oh, really?","TWN":"喔，是嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"아줌마 생각보다 어렸구나? 몰랐어!","JPN":"おばさんって思ったより若いんだね！　知らなかった！","ENG":"Guess you're younger than you look! Sorry! My bad!","TWN":"阿姨這麼年輕嗎？我之前不知道！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……너 지금 일부러 그러는 거지?","JPN":"……おまえ、それわざと言ってるんだろう。","ENG":"...You're doing that on purpose, aren't you?!","TWN":"……你是故意的吧？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러는 넌 누구야? 너야말로 여기서 못 보던 녀석인데?","JPN":"そういうおまえこそ誰だ？　初めて見る顔なんだが。","ENG":"Who are you? I've never seen you around here.","TWN":"你又是誰？我怎麼沒在這裡見過你？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라? 관리국 시설에 있으면서 나를 모른단 말이야?","JPN":"え？　管理局の施設にいながら私のことを知らないの？","ENG":"Huh? You work in an Administration facility and don't know who I am?","TWN":"喔？你在管理局竟然不認識我？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 널 꼭 알아야 하는 거야?","JPN":"おまえが誰だか知る必要があるのか？","ENG":"Do I have to know?","TWN":"我需要認識你嗎！？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"후후! 기대하시라!","JPN":"ふふ！　よーく聞きなさい！","ENG":"Haha! Behold!","TWN":"哼哼！那你就要給我聽好了！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"난 말이지! 관리국으로부터 최연소 전대장 제안까지 받았던 몸이라구!","JPN":"私はね、最年少にして管理局から戦隊長の提案を受けた者！","ENG":"I am the youngest person the Administration offered to become a division Commander!","TWN":"我就是……！管理局選的最年輕戰隊長！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"물론, 스승님과의 소중한 추억을 간직하기 위해 펜릴 전대에 남기로 했지만.","JPN":"もちろん、師匠との大切な思い出を守りたくてフェンリル戦隊に残ることにしたけどね。","ENG":"But of course, I decided to stay in the Fenrir Division to cherish the memories I have with Master.","TWN":"不過嘛，為了保留與師父珍貴的回憶，還是決定留在了芬里爾戰隊！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 놈의 전대장, 전대장! 지긋지긋하네!","JPN":"また戦隊長かよ、うんざりするなもう！","ENG":"Ugh, \\"Commander.\\" I hate that word!","TWN":"噢……戰隊長，戰隊長！我受夠這個詞了！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 그렇게나 대단한 거야?","JPN":"その戦隊長ってやつがそんなにすごいもんなのか？","ENG":"Is that really that big of a deal?","TWN":"戰隊長真的很了不起嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라, 아줌마 몰랐어?","JPN":"ええ？　おばさん知らないの？","ENG":"Oh, you don't know?","TWN":"嗯，阿姨你不知道嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"관리국으로부터 전대장 제안을 받는 다는 건…….","JPN":"管理局から戦隊長になるよう提案されるってことは……","ENG":"Being offered a Commander position by the Administration means–","TWN":"收到管理局的提案就等於……"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"수연아! 이수연!","JPN":"……キズナ！　カナミ・キズナ！","ENG":"Sooyeon! Lee Sooyeon!","TWN":"秀妍！李秀妍！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"수연아, 여긴 다른 전대가 주둔하고 있는 곳이니까 예의를 지켜야 한다고 했잖아.","JPN":"キズナ、ここは他の戦隊の駐屯地だから言動には気をつけるようにと言っただろう。","ENG":"Sooyeon, I told you to behave yourself because another division is stationed here.","TWN":"秀妍……我都告訴過你了，在其他戰隊的駐地要有禮貌……"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"뭐야, 멀대! 아직 나 아무 짓도 안 했거든?","JPN":"何だよ、ヒョロガリ！　私まだ何もしてないし。","ENG":"What, Beanstalk?! I didn't do anything yet!","TWN":"傻大個！我還什麼都沒做呢？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"하하, 안녕하세요? 야크샤 전대원 분이시죠?","JPN":"はは、すみません。ヤクシャー戦隊の方ですよね。","ENG":"Haha, hello. You're the Yaksha Division, right?","TWN":"哈哈，你好？你是夜叉戰隊的人吧？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어? 어어…….","JPN":"え？　あ、うん……","ENG":"Huh? Yeah...?","TWN":"呃？呃呃……"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"우리 수연이가 혹시 무슨 실례를 저지르지 않았나요?","JPN":"キズナが何か失礼なことを言いませんでしたか？","ENG":"Was our Sooyeon being rude to you?","TWN":"我們家秀妍沒有冒犯到你吧？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"아니, 보아하니 벌써 저지른 것 같네요.","JPN":"いや……その様子だと、もう言ってしまったようですね。","ENG":"Well, from the looks of it, she already did something.","TWN":"呃，看樣子是已經冒犯了呢。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}}]`);export{e as default};